-- =====================================================================
-- Phase 2 — venues become dynamic, family-editable data.
-- Run this once in the Supabase SQL editor (Project > SQL Editor).
--
-- Venues are readable by ANYONE (anon + authenticated) since they're the
-- core public content of the site, but only signed-in family members can
-- add/edit/delete them.
-- =====================================================================

create table if not exists public.venues (
  id text primary key,
  slug text not null,
  num text,
  name text not null,
  location text,
  theme text,
  vc text,
  vc_deep text,
  search_term text,
  site_url text,
  site_label text,
  ig_url text,
  ig_label text,
  one_liner text,
  lead text,
  why text,
  note text,
  moods jsonb not null default '[]'::jsonb,
  included jsonb not null default '[]'::jsonb,
  shots jsonb not null default '{}'::jsonb,
  order_index numeric not null default 0,
  created_by uuid references auth.users (id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.venues enable row level security;

create policy "venues are publicly readable"
  on public.venues for select
  to anon, authenticated
  using (true);

create policy "venues writable by signed-in users"
  on public.venues for all
  to authenticated
  using (true) with check (true);

