values ('castle', 'castle-farms', 'Venue 01', 'Castle Farms', 'Charlevoix, Michigan', 'Fairytale Castle', 'var(--orchid)', '#5F57C4', 'Castle Farms Charlevoix wedding', 'https://castlefarms.com/weddings/', 'castlefarms.com', 'https://www.instagram.com/castlefarms.weddings/', '@castlefarms.weddings', 'A real French-inspired castle in Northern Michigan — turrets, courtyards, and yes, a dragon.', 'Imagine saying “I do” inside a 1918 stone castle, ringed by formal gardens and Romanesque arches, with all the destination-wedding magic and none of the boarding passes.', 'It delivers fairytale, storybook energy that feels genuinely special — while staying an easy Midwest drive for your guests. Destination feel, hometown logistics.', 'a castle. with a dragon. need we say more?', '["Fairytale","Romantic","Elegant","No Passport"]'::jsonb, '[{"ic":"♟","title":"Five distinct spaces","desc":"Choose from grand halls and garden rooms — King''s Great Hall, the East & West Garden Rooms, the stone Knight''s Castle."},{"ic":"⛩","title":"Courtyard ceremonies","desc":"The Queen''s Courtyard (five soaring stone arches) or Knight''s Courtyard with a gazebo & fountain."},{"ic":"✨","title":"Coordinator + the basics","desc":"A dedicated venue coordinator, tables, chairs, white linens, candle centerpieces, and a bridal dressing suite."},{"ic":"🍽","title":"Bring your own vendors","desc":"Full flexibility to choose your caterer and pros (1918 Cellars house wine is used for wine service)."},{"ic":"👪","title":"Up to ~300 guests","desc":"Rooms scale from intimate micro-weddings to grand 300-guest celebrations."},{"ic":"🐉","title":"A whole estate to roam","desc":"Gardens, the largest outdoor model railroad in Michigan, and a dragon statue to hunt down."}]'::jsonb, '{"arrival":["the stone gatehouse + turrets at golden hour","guests walking the entrance drive","castle reflected in a courtyard fountain","close-up: ivy on the stone walls"],"ceremony":["Queen''s Courtyard arches set with white chairs","aisle view toward the stone arch","ring exchange under the crenellations","garden ceremony detail — florals on stone"],"reception":["King''s Great Hall with iron chandeliers","candlelit tablescape in a garden room","first dance under white chandeliers","French doors open to the courtyard at dusk"],"guest":["cocktail hour in the gardens","guests exploring the castle grounds","kids on the model railroad","bridal suite getting-ready moment"],"area":["downtown Charlevoix waterfront","a Lake Michigan sunset","the famous Mushroom Houses","a winery / boat-day afternoon"],"signature":["the dragon statue — obligatory photo","full castle facade, wide","turret + sky detail","the formal garden in bloom"]}'::jsonb, 1)
on conflict (id) do nothing;
