values ('beaches', 'beaches-turks', 'Venue 02', 'Beaches Turks & Caicos', 'Grace Bay, Providenciales', 'Family Vacation Paradise', 'var(--sea)', '#0A8A90', 'Beaches Turks and Caicos wedding Grace Bay', 'https://www.beaches.com/turks-caicos/weddings/', 'beaches.com', 'https://www.instagram.com/beachesresortsweddings/', '@beachesresortsweddings', 'A wedding and a family vacation rolled into one, on the world''s best beach.', 'Picture barefoot vows on 12 miles of powder-white sand, then a week of waterparks, snorkeling and 20-something restaurants so every guest — from toddlers to grandparents — has the trip of their life.', 'It''s the everyone''s-invited option: an all-inclusive resort where the celebration becomes a shared family vacation on legendary Grace Bay.', 'the whole crew, one beach, zero stress', '["Tropical","Family-Friendly","Fun","All-Inclusive"]'::jsonb, '[{"ic":"💒","title":"WeddingMoons packages","desc":"All-inclusive planning, ceremony setup, dining and photography — plus a dedicated wedding planner."},{"ic":"⛱","title":"Ceremony, your way","desc":"Beachfront, an oceanfront gazebo, the Garden of Love, or the Schooner Sunset Wedding Deck."},{"ic":"🍾","title":"Receptions big & small","desc":"From Key West Village to the Pavilion and Ballroom for larger celebrations."},{"ic":"🏊","title":"45,000 sq ft waterpark","desc":"Plus 10 pools, 15 bars, two Red Lane spas and a Kids Camp for infants to teens."},{"ic":"🍴","title":"20+ restaurants","desc":"Truly all-inclusive dining, from fine dining to a beachside jerk shack."},{"ic":"✈","title":"15 min from the airport","desc":"Six themed villages on one easy, walkable resort — short transfer, long memories."}]'::jsonb, '{"arrival":["resort arrival + welcome drink","the turquoise-water first view","a themed village lobby","beach cabana with your names on it"],"ceremony":["barefoot beach ceremony, ocean behind","oceanfront gazebo draped in white","aisle of petals on the sand","sunset vows silhouette"],"reception":["beachside reception, string lights","tablescape with sea-glass tones","dance floor under the stars","sparkler send-off on the sand"],"guest":["the waterpark in full swing","kids at Kids Camp","snorkeling on the reef","grandparents relaxing poolside"],"area":["aerial of Grace Bay''s 12-mile beach","a Providenciales excursion boat","conch shack / local flavor","a Caribbean sunset cruise"],"signature":["that impossibly turquoise water","the swim-up bar","whole-family group shot on the beach","Grace Bay from above"]}'::jsonb, 2)
